public class CustomEntityModel extends EntityModel<CustomEntity> {
    private final ModelPart root;
    public CustomEntityModel(ModelPart root) { this.root = root; }
    @Override
    public void render(MatrixStack matrices, VertexConsumer vertices, int light, int overlay, float red, float green, float blue, float alpha) {
        root.render(matrices, vertices, light, overlay, red, green, blue, alpha);
    }
    @Override
    public void setAngles(CustomEntity entity, float limbAngle, float limbDistance, float animationProgress, float headYaw, float headPitch) {}
}

public static TexturedModelData getTexturedModelData() {
    ModelData modelData = new ModelData();
    ModelPartData root = modelData.getRoot();
    root.addChild("body", ModelPartBuilder.create().uv(0, 0).cuboid(-4.0F, -4.0F, -4.0F, 8.0F, 8.0F, 8.0F), ModelTransform.pivot(0.0F, 16.0F, 0.0F));
    return TexturedModelData.of(modelData, 64, 32);
}

public class CustomEntityRenderer extends MobEntityRenderer<CustomEntity, CustomEntityModel> {
    private static final Identifier TEXTURE = new Identifier("modid", "textures/entity/custom.png");
    public CustomEntityRenderer(EntityRendererFactory.Context context) {
        super(context, new CustomEntityModel(CustomEntityModel.getTexturedModelData().createModel()), 0.5f);
    }
    @Override
    public Identifier getTexture(CustomEntity entity) { return TEXTURE; }
}

@Override
public void setAngles(CustomEntity entity, float limbAngle, float limbDistance, float animationProgress, float headYaw, float headPitch) {
    root.yaw = headYaw * 0.017453292F;
    root.pitch = headPitch * 0.017453292F;
    root.roll = (float)Math.sin(animationProgress * 0.1) * 0.1f;
}

float speed = Math.min(limbDistance * 0.5f, 1.0f);
leftLeg.pitch = (float)Math.sin(limbAngle * 0.6662f) * 0.5f * speed;
rightLeg.pitch = (float)Math.sin(limbAngle * 0.6662f + (float)Math.PI) * 0.5f * speed;

